  const products = await getCachedProducts();

  async function syncCatalog(formData: FormData) {
    'use server';
    // Invalidate the products cache
    revalidateTag('products');
    // In production, this would trigger the actual ERP/PIM sync job
    return { success: true, message: 'Sync initiated — catalog will refresh shortly.' };
